code = """import json\nimport re\nimport pandas as pd\n\nwith open(locals()['var_function-call-2241076992410809533'], 'r') as f:\n    civic_docs = json.load(f)\n\nwith open(locals()['var_function-call-15935162301044067236'], 'r') as f:\n    funding_records = json.load(f)\n\nprojects_extracted = []\n\n# Regex for (cid:190) like markers, escaped for python raw string and regex literal match\nCID_MARKER = r'\\(cid:\\d{{3}}\\\\)'\n\nfor doc in civic_docs:\n    text = doc['text']\n\n    # 1. Extract Disaster Recovery Projects\n    disaster_section_match = re.search(r'Disaster Recovery Projects\\n\\n(.*?)(?=\\n\\nCapital Improvement Projects|Page \\d+ of \\d+|$)', text, re.DOTALL)\n    if disaster_section_match:\n        disaster_text = disaster_section_match.group(1)\n        # Project pattern for disaster projects, capturing name and content until next project or end of section\n        # Project name characters: A-Z, a-z, 0-9, space, hyphen, ampersand, comma, dot, single quote, escaped brackets.\n        project_name_char_set = r'[A-Za-z0-9 \\-&,.\'\\[\\]]'\n        disaster_project_pattern = re.compile(\n            r'^(' + project_name_char_set + r'+? (?:Project|Plan))(?:\\n\\n' + CID_MARKER + r' Updates:(.*?)(?=\\n\\n' + project_name_char_set + r'+? (?:Project|Plan)|\\n\\n' + CID_MARKER + r' Project Schedule:|\\n\\n' + CID_MARKER + r' Project Description:|$))'\n            , re.DOTALL | re.MULTILINE\n        )\n        for match in disaster_project_pattern.finditer(disaster_text):\n            project_name = match.group(1).strip()\n            details = match.group(2).strip() if match.group(2) else ''\n            status = \"unknown\"\n\n            if re.search(r'completed|notice of completion', details, re.IGNORECASE):\n                status = \"completed\"\n            elif re.search(r'construction|under construction|begin construction|out to bid', details, re.IGNORECASE):\n                status = \"construction\"\n            elif re.search(r'design|preliminary design|FEMA/CalOES approval|consultant to finalize the design plans', details, re.IGNORECASE):\n                status = \"design\"\n            elif re.search(r'not started|identified in the .* Study|waiting for the agreement', details, re.IGNORECASE):\n                status = \"not started\"\n\n            projects_extracted.append({"Project_Name": project_name, "status": status, "topic": "disaster/FEMA/emergency"})\n\n    # 2. Extract Capital Improvement Projects that mention 'emergency' or 'FEMA'\n    capital_sections = {\n        'design': r'Capital Improvement Projects \\(Design\\)\n\\n(.*?)(?=\\n\\nCapital Improvement Projects|Disaster Recovery Projects|Page \\d+ of \\d+|$)',\n        'construction': r'Capital Improvement Projects \\(Construction\\)\n\\n(.*?)(?=\\n\\nCapital Improvement Projects|Disaster Recovery Projects|Page \\d+ of \\d+|$)',\n        'not started': r'Capital Improvement Projects \\(Not Started\\)\n\\n(.*?)(?=\\n\\nCapital Improvement Projects|Disaster Recovery Projects|Page \\d+ of \\d+|$)',\n    }\n\n    for status_key, pattern in capital_sections.items():\n        section_match = re.search(pattern, text, re.DOTALL)\n        if section_match:\n            section_text = section_match.group(1)\n            project_name_char_set = r'[A-Za-z0-9 \\-&,.\'\\[\\]]'\n            capital_project_pattern = re.compile(\n                r'^(' + project_name_char_set + r'+? (?:Project|Plan))(?:\\n\\n' + CID_MARKER + r' Updates:(.*?)(?=\\n\\n' + project_name_char_set + r'+? (?:Project|Plan)|\\n\\n' + CID_MARKER + r' Project Schedule:|\\n\\n' + CID_MARKER + r' Project Description:|$))'\n                , re.DOTALL | re.MULTILINE\n            )\n            for match in capital_project_pattern.finditer(section_text):\n                project_name = match.group(1).strip()\n                details = match.group(2).strip() if match.group(2) else ''\n                if re.search(r'emergency|FEMA', project_name + details, re.IGNORECASE):\n                    projects_extracted.append({"Project_Name": project_name, "status": status_key, "topic": "capital/emergency/FEMA"})\n\n    # 3. Handle specific projects mentioned in hints (if not already captured)\n    # Outdoor Warning Signs\n    if re.search(r'Outdoor Warning Signs', text) and re.search(r'emergency', text, re.IGNORECASE):\n        # Check if already added to avoid duplicates. More robust check later.\n        if not any(p['Project_Name'] == "Outdoor Warning Signs" for p in projects_extracted):\n            projects_extracted.append({"Project_Name": "Outdoor Warning Signs", "status": "design", "topic": "emergency"})\n\n    # Latigo Canyon Road Retaining Wall Repair Project\n    if re.search(r'Latigo Canyon Road Retaining Wall Repair Project', text) and re.search(r'FEMA/CalOES approval', text):\n        if not any(p['Project_Name'] == "Latigo Canyon Road Retaining Wall Repair Project" for p in projects_extracted):\n            projects_extracted.append({"Project_Name": "Latigo Canyon Road Retaining Wall Repair Project", "status": "design", "topic": "FEMA"})\n\n    # City Traffic Signals Backup Power\n    traffic_signals_match = re.search(r'City Traffic Signals Backup Power\\n\\n' + CID_MARKER + r' Project Description:(.*?)\\n\\n' + CID_MARKER + r' Updates:(.*?)\\n\\n' + CID_MARKER + r' Project Schedule:(.*?)(?=\\n\\n.+?$)', text, re.DOTALL)\n    if traffic_signals_match:\n        description = traffic_signals_match.group(1)\n        updates = traffic_signals_match.group(2)\n        if re.search(r'emergency', description + updates, re.IGNORECASE):\n            if not any(p['Project_Name'] == "City Traffic Signals Backup Power" for p in projects_extracted):\n                projects_extracted.append({"Project_Name": "City Traffic Signals Backup Power", "status": "preliminary design", "topic": "emergency"})\n\n# Convert to DataFrame for easier merging and deduplication\ndf_projects = pd.DataFrame(projects_extracted)\n# Drop duplicates, keeping the first occurrence. This implicitly handles cases where a project might be caught by multiple patterns.\ndf_projects.drop_duplicates(subset=['Project_Name'], inplace=True)\n\n# Load funding data into DataFrame\ndf_funding = pd.DataFrame(funding_records)\n\n# Merge the two DataFrames on Project_Name\n# Using an outer merge to keep all projects from both sides initially, then filter.\nmerged_df = pd.merge(df_projects, df_funding, on='Project_Name', how='left')\n\n# Filter for projects specifically related to 'emergency' or 'FEMA'\n# This is already somewhat handled by the extraction logic, but a final filter ensures correctness\n# and catches any edge cases where a project might have been extracted but without the topic being set correctly.\nfinal_projects = merged_df[merged_df['Project_Name'].str.contains('emergency|FEMA|CalOES|Disaster', case=False, na=False) | \n                             (merged_df['topic'].notna() & merged_df['topic'].str.contains('emergency|FEMA|disaster', case=False, na=False))].to_dict(orient='records')\n\n# Select and reorder columns for the final output\nresult = []\nfor project in final_projects:\n    result.append({\n        "Project_Name": project.get('Project_Name'),\n        "Funding_Source": project.get('Funding_Source'),\n        "Amount": project.get('Amount'),\n        "status": project.get('status')\n    })\n\nprint("__RESULT__:")\nprint(json.dumps(result))"""

